<?php
namespace Tests\Feature;
use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\EquippableItemValidator;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Str;use InvalidArgumentException;use Tests\TestCase;
class CharacterEquipmentStatsTest extends TestCase{use RefreshDatabase;private $origin=50000;private function character($attributes=[]){return Character::factory()->for(User::factory())->create(array_merge(['base_max_health'=>100,'current_health'=>100,'base_attack'=>10,'base_defense'=>5,'base_accuracy'=>80,'base_evasion'=>5,'base_critical_rate'=>'5.00'],$attributes));}private function equipment(Character $character,$bonuses=[],$refinement=0){$item=Item::create(array_merge(['code'=>'stats_'.Str::random(10),'name'=>'Equipo estadistico','item_type'=>'equipment','equipment_type'=>'weapon','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active'],$bonuses));$instance=ItemInstance::create(['uuid'=>(string)Str::uuid(),'character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>$refinement,'status'=>'available','origin_type'=>'legacy_inventory','origin_id'=>$this->origin++,'origin_unit_index'=>1,'acquired_at'=>now()]);return[$item,$instance];}public function test_no_equipment_preserves_base_stats(){$character=$this->character();$result=app(CharacterStatsCalculator::class)->breakdown($character);$this->assertSame(10,$result->effective()->attack());$this->assertSame(0,$result->equipment()->attack());$this->assertSame([],$result->equipmentSources());}public function test_equipment_adds_supported_stats_and_refinement_is_ignored(){list($item,$instance)=$this->equipment($character=$this->character(),['max_health_bonus'=>20,'attack_bonus'=>4,'defense_bonus'=>2,'accuracy_bonus'=>1,'evasion_bonus'=>3,'critical_chance_bonus'=>'2.25','attack_speed_bonus'=>'0.10'],7);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$result=app(CharacterStatsCalculator::class)->breakdown($character);$stats=$result->effective();$this->assertSame(120,$stats->maxHealth());$this->assertSame(100,$stats->currentHealth());$this->assertSame(14,$stats->attack());$this->assertSame(7,$stats->defense());$this->assertSame(81.0,$stats->accuracyRate());$this->assertSame(8.0,$stats->evasionRate());$this->assertSame(7.25,$stats->criticalChance());$this->assertSame(1.1,$stats->attackSpeed());$this->assertSame(7,$result->equipmentSources()[0]['refinement_level']);$this->assertSame(4,$result->equipmentSources()[0]['bonuses']['attack']);$this->assertSame(100,$character->fresh()->current_health);$instance->update(['refinement_level'=>0]);$this->assertSame(14,app(CharacterStatsCalculator::class)->calculate($character)->attack());}public function test_equip_and_unequip_never_change_current_health(){$character=$this->character(['current_health'=>90]);list($item,$instance)=$this->equipment($character,['max_health_bonus'=>50]);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$this->assertSame(90,$character->fresh()->current_health);app(CharacterEquipmentService::class)->unequip($character,'main_hand');$this->assertSame(90,$character->fresh()->current_health);}public function test_non_equipment_item_with_bonus_is_rejected(){$item=new Item(['item_type'=>'material','equipment_type'=>null,'is_stackable'=>true,'max_stack'=>10,'attack_bonus'=>1]);$this->expectException(InvalidArgumentException::class);app(EquippableItemValidator::class)->equipmentType($item);}public function test_character_view_renders_base_equipment_and_effective_values(){$this->seed(CharacterLevelRequirementSeeder::class);$character=$this->character();list($item,$instance)=$this->equipment($character,['attack_bonus'=>4]);app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$this->actingAs($character->user)->get(route('characters.show',$character))->assertOk()->assertSee('Estadísticas del personaje')->assertSee('Equipamiento')->assertSee('+4')->assertSee('<strong>14</strong>',false);}}
